import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../services/api';

function AdminDashboard({ user, onLogout }) {
  const [leaves, setLeaves] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    fetchPendingLeaves();
  }, []);

  const fetchPendingLeaves = async () => {
    try {
      const response = await api.get('/admin/leaves/pending/');
      setLeaves(response.data);
    } catch (err) {
      setError('Failed to load pending leaves');
    } finally {
      setLoading(false);
    }
  };

  const handleApprove = async (leaveId) => {
    try {
      await api.post(`/admin/leave/${leaveId}/approve/`);
      setLeaves(leaves.filter(leave => leave.id !== leaveId));
    } catch (err) {
      alert('Approval failed');
    }
  };

  const handleReject = async (leaveId) => {
    try {
      await api.post(`/admin/leave/${leaveId}/reject/`);
      setLeaves(leaves.filter(leave => leave.id !== leaveId));
    } catch (err) {
      alert('Rejection failed');
    }
  };

  const handleLogout = async () => {
    try {
      await api.post('/logout/');
      onLogout();
      navigate('/login');
    } catch (error) {
      console.error('Logout failed', error);
    }
  };

  if (loading) return <div style={styles.loading}>Loading...</div>;

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h2 style={styles.headerTitle}>Admin Dashboard - {user?.username}</h2>
        <button onClick={handleLogout} style={styles.logoutButton}>Logout</button>
      </div>

      <div style={styles.content}>
        <h3>Pending Leave Requests</h3>
        {error && <div style={styles.error}>{error}</div>}
        {leaves.length === 0 ? (
          <p>No pending leave requests.</p>
        ) : (
          <table style={styles.table}>
            <thead>
              <tr>
                <th>User</th>
                <th>Date</th>
                <th>Type</th>
                <th>Reason</th>
                <th>Applied On</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {leaves.map(leave => (
                <tr key={leave.id}>
                  <td>{leave.user_name}</td>
                  <td>{leave.date}</td>
                  <td>{leave.get_leave_type_display}</td>
                  <td>{leave.reason}</td>
                  <td>{new Date(leave.created_at).toLocaleString()}</td>
                  <td>
                    <button onClick={() => handleApprove(leave.id)} style={styles.approve}>Approve</button>
                    <button onClick={() => handleReject(leave.id)} style={styles.reject}>Reject</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}

const styles = {
  container: { padding: '30px', minHeight: '100vh' },
  header: {
    backgroundColor: 'var(--moss-dark)',
    color: 'white',
    padding: '20px 30px',
    borderRadius: '12px',
    marginBottom: '40px',
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    boxShadow: '0 3px 8px rgba(0,0,0,0.2)',
  },
  headerTitle: { margin: 0, fontSize: '26px', fontWeight: 500 },
  logoutButton: {
    backgroundColor: 'var(--moss-pale)',
    color: 'var(--moss-dark)',
    border: 'none',
    padding: '8px 25px',
    borderRadius: '25px',
    fontSize: '16px',
    cursor: 'pointer',
  },
  content: {
    backgroundColor: 'white',
    padding: '30px',
    borderRadius: '16px',
    border: '2px solid var(--moss-green)',
  },
  table: {
    width: '100%',
    borderCollapse: 'collapse',
    marginTop: '20px',
  },
  th: {
    border: '1px solid #ddd',
    padding: '12px',
    textAlign: 'left',
    backgroundColor: 'var(--moss-pale)',
  },
  td: {
    border: '1px solid #ddd',
    padding: '12px',
  },
  approve: {
    backgroundColor: '#2d6a4f',
    color: 'white',
    border: 'none',
    padding: '6px 12px',
    borderRadius: '6px',
    cursor: 'pointer',
    marginRight: '8px',
  },
  reject: {
    backgroundColor: '#b02a37',
    color: 'white',
    border: 'none',
    padding: '6px 12px',
    borderRadius: '6px',
    cursor: 'pointer',
  },
  error: {
    color: '#a94442',
    backgroundColor: '#f2dede',
    padding: '12px',
    borderRadius: '8px',
    marginBottom: '20px',
  },
  loading: { textAlign: 'center', padding: '40px' },
};

export default AdminDashboard;
